import { Helmet } from 'react-helmet';
import Header from './components/layout/Header';
import Hero from './components/hero/Hero';
import LeadForm from './components/form/LeadForm';
import Benefits from './components/sections/Benefits';
import Features from './components/sections/Features';
import Pricing from './components/sections/Pricing';
import Steps from './components/sections/Steps';
import FAQ from './components/sections/FAQ';
import FinalCTA from './components/sections/FinalCTA';
import Footer from './components/layout/Footer';

export default function App() {
  return (
    <>
      <Helmet>
        <title>Assurance Décennale Électricien | Devis Gratuit en Ligne</title>
        <meta name="description" content="Comparez et souscrivez votre assurance décennale électricien. Obligatoire selon la loi Spinetta. Devis gratuit et rapide. RC Pro incluse, protection 10 ans." />
        <meta name="keywords" content="assurance décennale électricien, assurance décennale artisan, assurance construction obligatoire, loi Spinetta, RC Pro électricien, garantie décennale, assurance electrician france" />
        <meta property="og:title" content="Assurance Décennale Électricien | Devis Gratuit" />
        <meta property="og:description" content="Comparez les meilleures offres d'assurance décennale pour electricien. Obligatoire selon la loi Spinetta. Devis gratuit sous 24h." />
        <meta property="og:type" content="website" />
        <meta property="og:url" content="https://decennale-pro.fr" />
        <meta name="twitter:card" content="summary_large_image" />
        <link rel="canonical" href="https://decennale-pro.fr" />
        <html lang="fr" />
      </Helmet>

      <div className="min-h-screen">
        <Header />
        <main>
          <Hero />
          <LeadForm />
          <Benefits />
          <Features />
          <Pricing />
          <Steps />
          <FAQ />
          <FinalCTA />
        </main>
        <Footer />
      </div>
    </>
  );
}
